func (rp *MemProvider) SessionExist(ctx context.Context, sid string) (bool, error) {
	if client == nil {
		if err := rp.connectInit(); err != nil {
			return false, err
		}
	}
	if item, err := client.Get(sid); err != nil || len(item.Value) == 0 {
		return false, err
	}
	return true, nil
}
